} from "remotion";

const blinkValue = (frame: number, startFrame: number, duration: number) => {
  const progress = (frame - startFrame) / duration;
  if (progress < 0 || progress > 1) {
    return 1;
  }

  return 1 - Math.sin(progress * Math.PI) * 0.96;
};

